// Safe template formula evaluator (no eval/exec)
// Supports: + - * /, parentheses, numeric literals, identifiers (e.g. price, quantity)

function evaluateTemplateFormula(template, context) {
  const match = template.match(/^\s*\{\{([\s\S]+)\}\}\s*$/);
  if (!match) throw new Error("Template must be in the form {{ expression }}");
  const expr = match[1].trim();

  const tokens = tokenize(expr);
  let i = 0;

  function peek() { return tokens[i]; }
  function consume(type) {
    const t = tokens[i];
    if (!t || (type && t.type !== type)) {
      throw new Error(`Unexpected token: ${t ? t.value : "EOF"}`);
    }
    i++;
    return t;
  }

  function parseExpression() {
    let node = parseTerm();
    while (peek() && (peek().value === "+" || peek().value === "-")) {
      const op = consume().value;
      const right = parseTerm();
      node = { type: "bin", op, left: node, right };
    }
    return node;
  }

  function parseTerm() {
    let node = parseFactor();
    while (peek() && (peek().value === "*" || peek().value === "/")) {
      const op = consume().value;
      const right = parseFactor();
      node = { type: "bin", op, left: node, right };
    }
    return node;
  }

  function parseFactor() {
    const t = peek();
    if (!t) throw new Error("Unexpected end of expression");

    if (t.type === "number") {
      consume("number");
      return { type: "num", value: t.value };
    }

    if (t.type === "ident") {
      consume("ident");
      return { type: "ident", value: t.value };
    }

    if (t.value === "(") {
      consume("op");
      const node = parseExpression();
      if (!peek() || peek().value !== ")") throw new Error("Missing ')'");
      consume("op");
      return node;
    }

    if (t.value === "-" || t.value === "+") {
      const op = consume("op").value;
      const factor = parseFactor();
      return { type: "unary", op, expr: factor };
    }

    throw new Error(`Unexpected token: ${t.value}`);
  }

  const ast = parseExpression();
  if (i !== tokens.length) throw new Error("Unexpected trailing tokens");

  return evalAst(ast, context);
}

function evalAst(node, context) {
  switch (node.type) {
    case "num":
      return node.value;
    case "ident": {
      if (!Object.prototype.hasOwnProperty.call(context, node.value)) {
        throw new Error(`Unknown variable: ${node.value}`);
      }
      const v = context[node.value];
      if (typeof v !== "number") throw new Error(`Variable ${node.value} must be a number`);
      return v;
    }
    case "unary": {
      const v = evalAst(node.expr, context);
      return node.op === "-" ? -v : +v;
    }
    case "bin": {
      const l = evalAst(node.left, context);
      const r = evalAst(node.right, context);
      if (node.op === "+") return l + r;
      if (node.op === "-") return l - r;
      if (node.op === "*") return l * r;
      if (node.op === "/") return l / r;
      throw new Error(`Unsupported operator: ${node.op}`);
    }
    default:
      throw new Error("Invalid AST node");
  }
}

function tokenize(expr) {
  const out = [];
  let i = 0;

  while (i < expr.length) {
    const ch = expr[i];

    if (/\s/.test(ch)) { i++; continue; }

